const payload = $json.body || $json;
const integrations = [
  'slack-notification',
  'email-alert',
  'sms-gateway',
  'erp-webhook',
  'weather-api',
  'satellite-feed'
];
if (!payload.integration || !integrations.includes(payload.integration)) {
  return { error: 'Unknown integration', available: integrations };
}
return { integration: payload.integration, payload: payload.data || {}, requestedAt: new Date().toISOString() };

const { integration, payload } = $json;
const endpoints = {
  'slack-notification': { url: process.env.SLACK_WEBHOOK_URL, method: 'POST' },
  'email-alert': { url: process.env.EMAIL_API_URL, method: 'POST' },
  'sms-gateway': { url: process.env.SMS_API_URL, method: 'POST' },
  'erp-webhook': { url: process.env.ERP_WEBHOOK_URL, method: 'POST' },
  'weather-api': { url: process.env.WEATHER_API_URL, method: 'GET' },
  'satellite-feed': { url: process.env.SATELLITE_API_URL, method: 'GET' }
};
return { ...$json, endpoint: endpoints[integration], status: 'forwarding' };

const { integration, endpoint, requestedAt } = $json;
return {
  status: 'delivered',
  integration,
  endpoint: endpoint ? endpoint.url : null,
  requestedAt,
  deliveredAt: new Date().toISOString()
};
